import React from 'react';
import { useAuth } from '../../context/AuthContext';
import StatCard from '../../components/common/StatCard';
import Card from '../../components/common/Card';
import Spinner from '../../components/common/Spinner';
import Badge from '../../components/common/Badge';
import { useDashboard } from '../../hooks/useDashboard';
import { useAttendance } from '../../hooks/useAttendance';
import { formatCurrency, formatTime, formatHours } from '../../utils/formatters';
import { MONTHS_RO } from '../../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import './DashboardPage.css';

const now = new Date();

const DashboardPage = () => {
  const { currentUser, isAdminOrManager } = useAuth();
  const { summary, deptStats, loading } = useDashboard(now.getFullYear(), now.getMonth() + 1);
  const { todayAttendance, loading: attLoading, checkIn, checkOut, actionLoading } = useAttendance();

  if (loading) return <Spinner size="lg" />;

  const isCheckedIn  = !!todayAttendance?.checkIn;
  const isCheckedOut = !!todayAttendance?.checkOut;

  const PIE_COLORS = ['#1e3a5f', '#22c55e', '#f59e0b', '#ef4444', '#3b82f6'];

  return (
    <div className="dashboard">
      {/* Greeting */}
      <div className="dashboard-greeting">
        <div>
          <h2>Bună ziua, {currentUser?.firstName}! 👋</h2>
          <p className="text-muted">
            {new Date().toLocaleDateString('ro-RO', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>
        </div>
      </div>

      {/* Employee: Check-in widget */}
      <Card className="dashboard-checkin">
        <div className="checkin-body">
          <div className="checkin-info">
            <h3>Status pontaj azi</h3>
            {attLoading ? <Spinner size="sm" /> : (
              <>
                <div className="checkin-status">
                  <Badge color={isCheckedIn ? 'success' : 'default'} dot>
                    {isCheckedIn ? 'Prezent' : 'Neînregistrat'}
                  </Badge>
                  {isCheckedIn && !isCheckedOut && (
                    <span className="checkin-since">
                      Din {formatTime(todayAttendance.checkIn)}
                    </span>
                  )}
                  {isCheckedOut && (
                    <span className="checkin-since">
                      {formatTime(todayAttendance.checkIn)} – {formatTime(todayAttendance.checkOut)}
                      {' '}({formatHours(todayAttendance.totalHours)})
                    </span>
                  )}
                </div>
                <div className="checkin-actions">
                  {!isCheckedIn && (
                    <button
                      className="checkin-btn checkin-btn-in"
                      onClick={checkIn}
                      disabled={actionLoading}
                    >
                      {actionLoading ? '⏳' : '▶'} Check-In
                    </button>
                  )}
                  {isCheckedIn && !isCheckedOut && (
                    <button
                      className="checkin-btn checkin-btn-out"
                      onClick={checkOut}
                      disabled={actionLoading}
                    >
                      {actionLoading ? '⏳' : '⏹'} Check-Out
                    </button>
                  )}
                </div>
              </>
            )}
          </div>
          <div className="checkin-shift">
            {currentUser?.shift ? (
              <>
                <p className="shift-label">Schimb curent</p>
                <p className="shift-name">{currentUser.shift.name}</p>
                <p className="shift-time">{currentUser.shift.startTime} – {currentUser.shift.endTime}</p>
              </>
            ) : <p className="text-muted">Niciun schimb alocat</p>}
          </div>
        </div>
      </Card>

      {/* Admin Stats */}
      {isAdminOrManager && summary && (
        <div className="dashboard-stats">
          <StatCard title="Total Angajați"    value={summary.totalEmployees}  icon="👥" color="primary" />
          <StatCard title="Angajați Activi"   value={summary.activeEmployees} icon="✅" color="success" />
          <StatCard title="Concedii Pending"  value={summary.pendingLeaves}   icon="🏖" color="warning" />
          <StatCard title="Costuri Lunare"    value={formatCurrency(summary.monthlyCosts)} icon="💰" color="info"
            subtitle={`${MONTHS_RO[now.getMonth()]} ${now.getFullYear()}`}
          />
          <StatCard title="Ore Lucrate"       value={`${summary.totalHoursWorked?.toFixed(0)}h`} icon="⏱" color="primary"
            subtitle="Luna curentă"
          />
        </div>
      )}

      {/* Charts – admin only */}
      {isAdminOrManager && deptStats?.length > 0 && (
        <div className="dashboard-charts">
          <Card padding={false} className="chart-card">
            <Card.Header>Angajați pe departamente</Card.Header>
            <Card.Body>
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={deptStats} margin={{ top: 10, right: 20, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                  <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                  <YAxis tick={{ fontSize: 12 }} />
                  <Tooltip />
                  <Bar dataKey="activeEmployees" name="Angajați activi" fill="var(--primary)" radius={[4,4,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </Card.Body>
          </Card>

          <Card padding={false} className="chart-card">
            <Card.Header>Distribuție salarială pe departamente</Card.Header>
            <Card.Body>
              <ResponsiveContainer width="100%" height={280}>
                <PieChart>
                  <Pie
                    data={deptStats}
                    dataKey="avgSalary"
                    nameKey="name"
                    cx="50%" cy="50%"
                    outerRadius={100}
                    label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    labelLine={false}
                    fontSize={11}
                  >
                    {deptStats.map((_, i) => (
                      <Cell key={i} fill={PIE_COLORS[i % PIE_COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip formatter={(v) => formatCurrency(v)} />
                </PieChart>
              </ResponsiveContainer>
            </Card.Body>
          </Card>
        </div>
      )}
    </div>
  );
};

export default DashboardPage;
